import * as aws from '@pulumi/aws';
import * as pulumi from '@pulumi/pulumi';

const config = new pulumi.Config();
const env = pulumi.getStack();
const replicas = config.requireNumber('replicas');

interface ServiceArgs {
  name: string;
  image: pulumi.Input<string>;
  cpu: number;
  memory: number;
  port: number;
  replicas: number;
  publiclyAccessible: boolean;
}

class EcsService extends pulumi.ComponentResource {
  public readonly service: aws.ecs.Service;
  constructor(name: string, args: ServiceArgs, opts?: pulumi.ComponentResourceOptions) {
    super('acme:ecs:Service', name, {}, opts);

    const taskDef = new aws.ecs.TaskDefinition(`${name}-task`, {
      family: args.name,
      requiresCompatibilities: ['FARGATE'],
      networkMode: 'awsvpc',
      cpu: args.cpu.toString(),
      memory: args.memory.toString(),
      executionRoleArn: executionRole.arn,
      taskRoleArn: taskRole.arn,
      containerDefinitions: pulumi.jsonStringify([{
        name: 'app',
        image: args.image,
        portMappings: [{ containerPort: args.port }],
        essential: true,
        readonlyRootFilesystem: true,
        logConfiguration: {
          logDriver: 'awslogs',
          options: {
            'awslogs-group': `/ecs/${args.name}`,
            'awslogs-region': aws.config.region!,
            'awslogs-stream-prefix': 'app',
          },
        },
      }]),
    }, { parent: this });

    this.service = new aws.ecs.Service(name, {
      cluster: cluster.arn,
      taskDefinition: taskDef.arn,
      desiredCount: args.replicas,
      launchType: 'FARGATE',
      deploymentMaximumPercent: 200,
      deploymentMinimumHealthyPercent: 100,
      deploymentCircuitBreaker: { enable: true, rollback: true },
      networkConfiguration: {
        subnets: privateSubnets,
        securityGroups: [serviceSg.id],
        assignPublicIp: false,
      },
    }, { parent: this });
  }
}

const api = new EcsService('api', {
  name: `api-${env}`,
  image: `ghcr.io/acme/api:${config.require('imageTag')}`,
  cpu: 512,
  memory: 1024,
  port: 3000,
  replicas,
  publiclyAccessible: env === 'prod' ? true : false,
});

export const serviceName = api.service.name;
export const taskDefArn = api.service.taskDefinition;

