        -Server
    }

    @auth_paths path /api/auth/*
    rate_limit @auth_paths {
        zone authzone
        key {http.request.remote.host}
        events 5
        window 1s
    }

    @api_paths path /api/*
    rate_limit @api_paths {
        zone apizone
        key {http.request.remote.host}
        events 100
        window 1s
    }

    reverse_proxy localhost:3000 {
        header_up Host {host}
        header_up X-Real-IP {remote_host}
        header_up X-Forwarded-Proto https
        transport http {
            keepalive 60s
            keepalive_idle_conns 100
        }
    }
}

const { ComputeOptimizerClient, GetECSServiceRecommendationsCommand } = require('@aws-sdk/client-compute-optimizer');
const { CloudWatchClient, GetMetricStatisticsCommand } = require('@aws-sdk/client-cloudwatch');
const { Octokit } = require('@octokit/rest');

const FARGATE_VALID_COMBOS = [
  [256, [512, 1024, 2048]],
  [512, [1024, 2048, 3072, 4096]],
  [1024, [2048, 3072, 4096, 5120, 6144, 7168, 8192]],
  [2048, [4096, 5120, 6144, 7168, 8192, ...Array(5).fill(0).map((_,i) => 9216 + i*1024)]],
  [4096, Array(23).fill(0).map((_,i) => 8192 + i*1024)],
];

function nextValidFargate(cpu, memory) {
  const cpuVal = FARGATE_VALID_COMBOS.find(([c]) => c >= cpu)?.[0] || 4096;
  const validMems = FARGATE_VALID_COMBOS.find(([c]) => c === cpuVal)[1];
  const memVal = validMems.find(m => m >= memory) || validMems[validMems.length-1];
  return { cpu: cpuVal, memory: memVal };
}

exports.handler = async () => {
  const co = new ComputeOptimizerClient({});
  const recs = await co.send(new GetECSServiceRecommendationsCommand({}));
  const octokit = new Octokit({ auth: process.env.GH_TOKEN });

  for (const rec of recs.ecsServiceRecommendations || []) {
    const top = rec.serviceRecommendationOptions?.[0];
    if (!top) continue;
    if (rec.finding === 'Optimized') continue;

    const recommendedCpu = parseInt(top.cpu);
    const recommendedMem = parseInt(top.memory);
    const withHeadroom = nextValidFargate(
      Math.ceil(recommendedCpu * 1.3),
      Math.ceil(recommendedMem * 1.3)
    );

    const currentCpu = parseInt(rec.currentServiceConfiguration.cpu);
    const currentMem = parseInt(rec.currentServiceConfiguration.memory);
    if (withHeadroom.cpu === currentCpu && withHeadroom.memory === currentMem) continue;

    const serviceName = rec.serviceArn.split('/').pop();
    const monthlySavings = top.estimatedMonthlySavings?.value || 0;

    await octokit.pulls.create({
      owner: 'acme',
      repo: 'infra',
      title: `[Rightsize] ${serviceName}: ${currentCpu}/${currentMem} → ${withHeadroom.cpu}/${withHeadroom.memory}`,
      head: `rightsize/${serviceName}-${Date.now()}`,
      base: 'main',
      body: `Compute Optimizer recommends downsize.\n\nCurrent: ${currentCpu} CPU / ${currentMem} MB\nRecommended (+30% headroom): ${withHeadroom.cpu} CPU / ${withHeadroom.memory} MB\nEstimated monthly savings: $${monthlySavings}\n\nCloudWatch evidence: <link>`,
    });
  }
};

