const fetch = require('node-fetch');

exports.handler = async () => {
  const sentryErrors = await fetch(`https://sentry.io/api/0/projects/acme/api/stats/?stat=received&resolution=1m&since=${Math.floor(Date.now()/1000) - 3600}`, { headers: { Authorization: `Bearer ${process.env.SENTRY_TOKEN}` }}).then(r => r.json());
  const recent = sentryErrors.slice(-10).reduce((s, x) => s + x[1], 0);
  const prior = sentryErrors.slice(-60, -10).reduce((s, x) => s + x[1], 0) / 5;
  if (recent <= prior * 2) return { ok: true };

  const flagChanges = await fetch(`${process.env.UNLEASH_URL}/api/admin/events?since=${new Date(Date.now() - 30*60*1000).toISOString()}`, { headers: { Authorization: process.env.UNLEASH_TOKEN }}).then(r => r.json());
  const recentToggle = flagChanges.events.find(e => e.type === 'feature-strategy-updated' || e.type === 'feature-enabled');
  if (!recentToggle) return { ok: true, note: 'error spike but no recent flag change' };

  await fetch(`${process.env.UNLEASH_URL}/api/admin/projects/default/features/${recentToggle.featureName}/environments/production/off`, { method: 'POST', headers: { Authorization: process.env.UNLEASH_TOKEN }});
  await fetch(process.env.SLACK_WEBHOOK, { method: 'POST', body: JSON.stringify({ text: `:rotating_light: Auto-disabled flag ${recentToggle.featureName} after error spike` })});
};

